#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int *parent;
int *setSize;

int dsuFind(int a) {
    if (parent[a] == a) return a;
    return parent[a] = dsuFind(parent[a]);
}

void dsuUnion(int a, int b) {
    int ra = dsuFind(a);
    int rb = dsuFind(b);
    if (ra == rb) return;
    if (setSize[ra] < setSize[rb]) {
        int tmp = ra; ra = rb; rb = tmp;
    }
    parent[rb] = ra;
    setSize[ra] += setSize[rb];
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n, m; scanf("%d %d", &n, &m);
        parent = (int*)malloc(n * sizeof(int));
        setSize = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) { parent[i] = i; setSize[i] = 1; }
        for (int i = 0; i < m; ++i) {
            char cmd[10]; scanf("%s", cmd);
            if (strcmp(cmd, "union") == 0) {
                int a, b; scanf("%d %d", &a, &b);
                dsuUnion(a, b);
            } else { // find
                int a; scanf("%d", &a);
                printf("%d\n", dsuFind(a));
            }
        }
        free(parent);
        free(setSize);
    }
    return 0;
}

