import sys

def solve():
    data = sys.stdin.buffer.read().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx]); idx += 1
    out = []
    for _ in range(T):
        n, m = map(int, data[idx].split()); idx += 1
        parent = list(range(n))
        size = [1]*n
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a,b):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if size[ra] < size[rb]:
                ra, rb = rb, ra
            parent[rb] = ra
            size[ra] += size[rb]
        for _ in range(m):
            parts = data[idx].split(); idx += 1
            if parts[0] == b'union':
                union(int(parts[1]), int(parts[2]))
            else:  # find
                out.append(str(find(int(parts[1]))))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

